[FormDataSourceEventHandler(formDataSourceStr(CustFreeInvoice, CustInvoiceTable), FormDataSourceEventType::Activated)]
public static void CustInvoiceTable_OnActivated(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormRun formRun = sender.formRun();


    FormStringControl paymentControl = formRun.control(formRun.controlId("GroupPayment_PaymentCV")) as FormStringControl;


    if (paymentControl)
    {
        paymentControl.mandatory(true);
    }

    if (ETG_Parameters::find().ETGDocumentDate == NoYes::Yes)
    {
        sender.object(fieldNum(CustInvoiceTable, DocumentDate)).mandatory(true);
    }
    else
    {
        sender.object(fieldNum(CustInvoiceTable, DocumentDate)).mandatory(false);
    }


}
